import { usePredictionStore } from "../stores/usePredictionStore";
import { useBotStore } from "../stores/useBotStore";
import { useOfflineStore } from "../stores/useOfflineStore";

/**
 * DataReconciliationService - Centralized service for data synchronization
 *
 * Handles merging of cached and fresh data when connection is restored.
 * Implements smart merging strategies based on timestamps and data types.
 */
class DataReconciliationService {
  private isReconciling = false;

  /**
   * Reconcile all stores
   * Called when connection is restored
   */
  async reconcileAll(): Promise<void> {
    if (this.isReconciling) {
      return;
    }

    const offlineStore = useOfflineStore.getState();

    // Only reconcile if we're online and backend is available
    if (!offlineStore.isOnline || !offlineStore.isBackendAvailable) {
      return;
    }

    this.isReconciling = true;

    try {
      // Run reconciliations in parallel for efficiency
      await Promise.all([this.reconcilePredictions(), this.reconcileBotData()]);

      offlineStore.updateLastSync();
    } catch (_error) {
      // ignore individual reconciliation errors
    } finally {
      this.isReconciling = false;
    }
  }

  /**
   * Reconcile predictions and leagues data
   */
  async reconcilePredictions(): Promise<void> {
    const predictionStore = usePredictionStore.getState();

    try {
      // Refetch leagues (lightweight, background)
      await predictionStore.fetchLeagues(true);

      // If a league is selected, refetch its predictions (silently)
      if (predictionStore.selectedLeague) {
        await predictionStore.fetchPredictions(true);
      }
    } catch (_error) {
      // Don't throw - allow other reconciliations to continue
    }
  }

  /**
   * Reconcile bot dashboard data
   */
  async reconcileBotData(): Promise<void> {
    const botStore = useBotStore.getState();

    try {
      // Use the store's built-in reconcile method
      await botStore.reconcile();
    } catch (_error) {
      // Don't throw - keep using cached data
    }
  }

  /**
   * Check if data needs reconciliation
   * @param lastSyncTimestamp - Last sync timestamp
   * @param thresholdMinutes - Threshold in minutes (default: 5)
   */
  needsReconciliation(
    lastSyncTimestamp: number | null,
    thresholdMinutes: number = 5
  ): boolean {
    if (!lastSyncTimestamp) return true;

    const now = Date.now();
    const threshold = thresholdMinutes * 60 * 1000; // Convert to milliseconds

    return now - lastSyncTimestamp > threshold;
  }

  /**
   * Get reconciliation status
   */
  isReconciliationInProgress(): boolean {
    return this.isReconciling;
  }
}

// Singleton instance
export const dataReconciliationService = new DataReconciliationService();

import { create } from "zustand";
import { persist, createJSONStorage } from "zustand/middleware";
import { LiveMatchPrediction } from "../../domain/entities";
import { liveApi } from "../../infrastructure/api/live";
import { indexedDBStorage } from "../../infrastructure/storage/indexedDBStorage";
import { useOfflineStore } from "./useOfflineStore";

interface LiveState {
  matches: LiveMatchPrediction[];
  loading: boolean;
  error: string | null;
  pollingIntervalId: NodeJS.Timeout | null;

  // Actions
  fetchMatches: () => Promise<void>;
  startPolling: (intervalMs?: number) => void;
  stopPolling: () => void;
}

// Cleanup old localStorage to prevent quota issues on mobile
try {
  if (typeof window !== "undefined") {
    localStorage.removeItem("live-matches-storage");
  }
} catch (e) {
  // Silent cleanup fail
}

export const useLiveStore = create<LiveState>()(
  persist(
    (set, get) => ({
      matches: [],
      loading: false,
      error: null,
      pollingIntervalId: null,

      fetchMatches: async () => {
        // Only set loading true on first load to avoid flickering
        if (get().matches.length === 0) {
          set({ loading: true });
        }

        try {
          // Intentionally waiting a bit to prevent rapid flickering if called frequently
          // await new Promise(resolve => setTimeout(resolve, 600));
          // Removing artificial delay for store - let UI decide if it needs to wait or show skeleton

          const matches = await liveApi.getLiveMatchesWithPredictions();
          set({ matches, error: null });

          useOfflineStore.getState().setBackendAvailable(true);
          useOfflineStore.getState().updateLastSync();
        } catch (err: unknown) {
          const error =
            err instanceof Error ? err : new Error("Error desconocido");
          const isNetworkError =
            error.message === "Network Error" ||
            (err as { code?: string })?.code === "ERR_NETWORK" ||
            (err as { code?: string })?.code === "ECONNABORTED";
          if (isNetworkError) {
            useOfflineStore.getState().setBackendAvailable(false);
          }

          // Suppress technical error string if it's a network issue
          set({
            error: isNetworkError
              ? null
              : error.message || "Error al cargar partidos en vivo",
          });
        } finally {
          set({ loading: false });
        }
      },

      startPolling: (intervalMs = 60000) => {
        const { stopPolling, fetchMatches } = get();
        stopPolling(); // Ensure no duplicate intervals

        fetchMatches(); // Initial fetch

        const intervalId = setInterval(() => {
          fetchMatches();
        }, intervalMs);

        set({ pollingIntervalId: intervalId });
      },

      stopPolling: () => {
        const { pollingIntervalId } = get();
        if (pollingIntervalId) {
          clearInterval(pollingIntervalId);
          set({ pollingIntervalId: null });
        }
      },
    }),
    {
      name: "live-matches-storage-v2",
      storage: createJSONStorage(() => indexedDBStorage),
      partialize: (state) => ({
        matches: state.matches,
      }),
    }
  )
);

import { create } from "zustand";
import { persist, createJSONStorage } from "zustand/middleware";
import { MatchPrediction } from "../../domain/entities";

export interface ParleyPickItem {
  match: MatchPrediction;
  pick: string;
  probability: number;
  label: string;
}

interface ParleyState {
  selectedPicks: Record<string, ParleyPickItem>;

  // Actions
  addPick: (matchId: string, pick: ParleyPickItem) => void;
  removePick: (matchId: string) => void;
  clearPicks: () => void;
  togglePick: (match: MatchPrediction, pick?: ParleyPickItem | null) => void;
}

// Cleanup old localStorage to prevent quota issues on mobile
try {
  if (typeof window !== "undefined") {
    localStorage.removeItem("parley-storage");
  }
} catch (e) {
  // Silent cleanup fail
}

export const useParleyStore = create<ParleyState>()(
  persist(
    (set, get) => ({
      selectedPicks: {},

      addPick: (matchId, pick) =>
        set((state) => {
          if (Object.keys(state.selectedPicks).length >= 10) {
            return state;
          }
          return {
            selectedPicks: {
              ...state.selectedPicks,
              [matchId]: pick,
            },
          };
        }),

      removePick: (matchId) =>
        set((state) => {
          const newPicks = { ...state.selectedPicks };
          delete newPicks[matchId];
          return { selectedPicks: newPicks };
        }),

      clearPicks: () => set({ selectedPicks: {} }),

      togglePick: (match, pick) => {
        const matchId = match.match.id;
        const state = get();
        if (state.selectedPicks[matchId]) {
          state.removePick(matchId);
        } else if (pick) {
          state.addPick(matchId, pick);
        }
      },
    }),
    {
      name: "parley-storage-v3", // Bump version to reset invalid state
      storage: createJSONStorage(() => localStorage), // Switch to localStorage for speed
    }
  )
);

import { create } from "zustand";
import { persist, createJSONStorage } from "zustand/middleware";
import {
  LeaguesResponse,
  MatchPrediction,
  Country,
  League,
} from "../../domain/entities";
import { predictionsApi } from "../../infrastructure/api/predictions";
import { leaguesApi } from "../../infrastructure/api/leagues";
import { useOfflineStore } from "./useOfflineStore";
import { indexedDBStorage } from "../../infrastructure/storage/indexedDBStorage";

export type SortOption =
  | "confidence"
  | "date"
  | "home_probability"
  | "away_probability";

interface PredictionState {
  // Data
  leaguesData: LeaguesResponse | null;
  selectedCountry: Country | null;
  selectedLeague: League | null;
  predictions: MatchPrediction[];
  searchMatches: MatchPrediction[]; // For search results

  // UI/Filter State
  searchQuery: string;
  sortBy: SortOption;
  sortDesc: boolean;

  // Status
  leaguesLoading: boolean;
  leaguesError: string | null;
  predictionsLoading: boolean;
  predictionsError: string | null;
  searchLoading: boolean;

  // Training Status
  lastTrainingUpdate: string | null;
  newPredictionsAvailable: boolean;

  // Actions
  fetchLeagues: (background?: boolean) => Promise<void>;
  selectCountry: (country: Country | null) => void;
  selectLeague: (league: League | null) => void;
  fetchPredictions: (background?: boolean) => Promise<void>;
  setSearchQuery: (query: string) => void;
  setSortBy: (sort: SortOption) => void;
  resetFilters: () => void;
  performSearch: (query: string) => Promise<void>;
  checkTrainingStatus: () => Promise<void>;
}

// Cleanup old localStorage to prevent quota issues on mobile
try {
  if (typeof window !== "undefined") {
    localStorage.removeItem("prediction-storage");
  }
} catch (e) {
  // Silent cleanup fail
}

export const usePredictionStore = create<PredictionState>()(
  persist(
    (set, get) => ({
      leaguesData: null,
      selectedCountry: null,
      selectedLeague: null,
      predictions: [],
      searchMatches: [],

      searchQuery: "",
      sortBy: "confidence",
      sortDesc: true,

      leaguesLoading: false,
      leaguesError: null,
      predictionsLoading: false,
      predictionsError: null,
      searchLoading: false,

      lastTrainingUpdate: null,
      newPredictionsAvailable: false,

      fetchLeagues: async (background = false) => {
        if (!background) {
          set({ leaguesLoading: true, leaguesError: null });
        }
        try {
          const data = await leaguesApi.getLeagues();
          // Filter out excluded countries
          const excludedCountries = [
            "Turkey",
            "Greece",
            "Scotland",
            "Belgium",
            "Turquía",
            "Grecia",
            "Escocia",
            "Bélgica",
          ];
          const filteredCountries = data.countries
            .filter((c) => !excludedCountries.includes(c.name))
            .sort((a, b) => a.name.localeCompare(b.name));

          set({
            leaguesData: {
              ...data,
              countries: filteredCountries,
            },
          });

          // Successful fetch means backend is likely available
          useOfflineStore.getState().setBackendAvailable(true);
          useOfflineStore.getState().updateLastSync();
        } catch (err: unknown) {
          const error =
            err instanceof Error ? err : new Error("Error desconocido");
          // Check for network error / unreachable backend
          const isNetworkError =
            error.message === "Network Error" ||
            (err as { code?: string })?.code === "ERR_NETWORK" ||
            (err as { code?: string })?.code === "ECONNABORTED";
          if (isNetworkError) {
            useOfflineStore.getState().setBackendAvailable(false);
          }

          // If we have a network error, we don't set leaguesError to avoid showing the red alert box.
          // The global OfflineIndicator will show the orange "Limited Connection" bar.
          set({
            leaguesError: isNetworkError
              ? null
              : error.message || "Error al cargar las ligas",
          });
        } finally {
          if (!background) {
            set({ leaguesLoading: false });
          }
        }
      },

      selectCountry: (country) => {
        set({
          selectedCountry: country,
          selectedLeague: null,
          predictions: [], // Clear predictions when country changes
          predictionsError: null,
        });
      },

      selectLeague: (league) => {
        set({
          selectedLeague: league,
          // Don't clear predictions immediately if we want to show cached ones while loading
          // predictions: [],
          predictionsError: null,
          searchQuery: "", // Clear search when changing league
          searchMatches: [],
        });
        if (league) {
          get().fetchPredictions();
        }
      },

      fetchPredictions: async (background = false) => {
        const { selectedLeague, sortBy, sortDesc } = get();
        if (!selectedLeague) {
          set({ predictions: [] });
          return;
        }

        if (!background) {
          set({ predictionsLoading: true, predictionsError: null });
        }

        try {
          const response = await predictionsApi.getPredictions(
            selectedLeague.id,
            30,
            sortBy,
            sortDesc
          );
          set({ predictions: response.predictions });

          // Predictions are fetched fresh each time, no need to persist
          useOfflineStore.getState().setBackendAvailable(true);
          useOfflineStore.getState().updateLastSync();
        } catch (err: unknown) {
          const error =
            err instanceof Error ? err : new Error("Error desconocido");
          const isNetworkError =
            error.message === "Network Error" ||
            (err as { code?: string })?.code === "ERR_NETWORK";
          if (isNetworkError) {
            useOfflineStore.getState().setBackendAvailable(false);
          }

          // If we have a network error, we don't set predictionsError to avoid technical alerts.
          set({
            predictionsError: isNetworkError
              ? null
              : error.message || "Error al cargar las predicciones",
          });
        } finally {
          if (!background) {
            set({ predictionsLoading: false });
          }
        }
      },

      setSearchQuery: (query) => {
        set({ searchQuery: query });
        if (query.length > 2) {
          get().performSearch(query);
        } else {
          set({ searchMatches: [] });
        }
      },

      performSearch: async (query) => {
        set({ searchLoading: true });
        try {
          const matchPredictions = await predictionsApi.getTeamMatches(query);
          set({ searchMatches: matchPredictions });
          useOfflineStore.getState().setBackendAvailable(true);
        } catch (err: unknown) {
          const error =
            err instanceof Error ? err : new Error("Error desconocido");
          const isNetworkError =
            error.message === "Network Error" ||
            (err as { code?: string })?.code === "ERR_NETWORK";
          if (isNetworkError) {
            useOfflineStore.getState().setBackendAvailable(false);
          }
          set({ searchMatches: [] });
        } finally {
          set({ searchLoading: false });
        }
      },

      checkTrainingStatus: async () => {
        try {
          const status = await predictionsApi.getTrainingStatus();
          const { lastTrainingUpdate } = get();

          if (status.last_update && status.last_update !== lastTrainingUpdate) {
            // New update detected
            set({ lastTrainingUpdate: status.last_update });

            // If we had a previous update (not first load), warn user and refresh
            if (lastTrainingUpdate !== null) {
              set({ newPredictionsAvailable: true });
              // Refresh data silently
              get().fetchPredictions(true);
              // Reset notification flag after 5s or let UI handle it
              setTimeout(() => set({ newPredictionsAvailable: false }), 5000);
            }
          }
        } catch (error) {
          // Silent fail on background check
        }
      },

      setSortBy: (sortBy) => {
        set({ sortBy });
        if (get().selectedLeague) {
          get().fetchPredictions();
        }
      },

      resetFilters: () => {
        set({ selectedCountry: null, selectedLeague: null, searchQuery: "" });
      },
    }),
    {
      name: "prediction-storage-v2", // unique name
      storage: createJSONStorage(() => indexedDBStorage),
      // Only persist essential user selections, NOT large data arrays
      partialize: (state) => ({
        // leaguesData is persisted separately via localStorageObserver
        selectedCountry: state.selectedCountry,
        selectedLeague: state.selectedLeague,
        sortBy: state.sortBy,
        sortDesc: state.sortDesc,
        lastTrainingUpdate: state.lastTrainingUpdate,
      }),
    }
  )
);

