import { useState, useEffect } from "react";

/**
 * Extend window type for PWA install event
 */
declare global {
  interface WindowEventMap {
    beforeinstallprompt: BeforeInstallPromptEvent;
  }
  interface BeforeInstallPromptEvent extends Event {
    prompt: () => Promise<void>;
    userChoice: Promise<{ outcome: "accepted" | "dismissed" }>;
  }
}

export const usePWAInstall = () => {
  const [installPrompt, setInstallPrompt] =
    useState<BeforeInstallPromptEvent | null>(null);
  const [isInstalled, setIsInstalled] = useState(false);

  useEffect(() => {
    const handler = (e: BeforeInstallPromptEvent) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener("beforeinstallprompt", handler);

    if (window.matchMedia("(display-mode: standalone)").matches) {
      setIsInstalled(true);
    }

    return () => window.removeEventListener("beforeinstallprompt", handler);
  }, []);

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    await installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === "accepted") {
      setIsInstalled(true);
    }
    setInstallPrompt(null);
  };

  return { installPrompt, isInstalled, handleInstallClick };
};

import { useEffect, useRef, useCallback } from "react";

interface UseSmartPollingOptions {
  /** Polling interval in milliseconds */
  intervalMs: number;
  /** Callback to execute on each poll */
  onPoll: () => Promise<void> | void;
  /** Whether polling is enabled */
  enabled?: boolean;
  /** Maximum backoff multiplier on errors */
  maxBackoffMultiplier?: number;
}

/**
 * Smart polling hook with visibility awareness and exponential backoff.
 *
 * Features:
 * - Pauses polling when browser tab is not visible (Page Visibility API)
 * - Uses exponential backoff on errors (up to maxBackoffMultiplier)
 * - Cleans up on unmount
 * - Immediately polls when tab becomes visible after being hidden
 */
export function useSmartPolling({
  intervalMs,
  onPoll,
  enabled = true,
  maxBackoffMultiplier = 4,
}: UseSmartPollingOptions) {
  const intervalRef = useRef<number | null>(null);
  const backoffMultiplier = useRef(1);
  const isVisibleRef = useRef(!document.hidden);
  const lastPollTimeRef = useRef<number>(0);

  const poll = useCallback(async () => {
    if (!isVisibleRef.current || !enabled) return;

    try {
      await onPoll();
      backoffMultiplier.current = 1; // Reset backoff on success
      lastPollTimeRef.current = Date.now();
    } catch {
      // Increase backoff on error (max 4x)
      backoffMultiplier.current = Math.min(
        backoffMultiplier.current * 2,
        maxBackoffMultiplier
      );
    }
  }, [onPoll, enabled, maxBackoffMultiplier]);

  const startPolling = useCallback(() => {
    if (intervalRef.current) return;

    const effectiveInterval = intervalMs * backoffMultiplier.current;

    intervalRef.current = window.setInterval(() => {
      poll();
    }, effectiveInterval);
  }, [intervalMs, poll]);

  const stopPolling = useCallback(() => {
    if (intervalRef.current) {
      window.clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }, []);

  // Handle visibility change
  useEffect(() => {
    const handleVisibilityChange = () => {
      isVisibleRef.current = !document.hidden;

      if (document.hidden) {
        // Tab is hidden - stop polling to save resources
        stopPolling();
      } else {
        // Tab is visible again
        const timeSinceLastPoll = Date.now() - lastPollTimeRef.current;

        // If it's been longer than the interval, poll immediately
        if (timeSinceLastPoll > intervalMs) {
          poll();
        }

        // Resume polling
        if (enabled) {
          startPolling();
        }
      }
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);

    return () => {
      document.removeEventListener("visibilitychange", handleVisibilityChange);
    };
  }, [intervalMs, poll, startPolling, stopPolling, enabled]);

  // Start/stop polling based on enabled state
  useEffect(() => {
    if (enabled && isVisibleRef.current) {
      // Initial poll
      poll();
      startPolling();
    } else {
      stopPolling();
    }

    return () => {
      stopPolling();
    };
  }, [enabled, poll, startPolling, stopPolling]);

  return {
    /** Force an immediate poll */
    pollNow: poll,
    /** Current backoff multiplier (for debugging) */
    backoffMultiplier: backoffMultiplier.current,
  };
}

import { useState, useEffect } from "react";
import api from "../services/api";
import { MatchPrediction } from "../types";

export function useTeamSearch() {
  const [searchQuery, setSearchQuery] = useState<string>("");
  const [searchMatches, setSearchMatches] = useState<MatchPrediction[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const delayDebounceFn = setTimeout(async () => {
      if (searchQuery.length > 2) {
        setLoading(true);
        try {
          const matches = await api.getTeamMatches(searchQuery);
          // Transform API Match to MatchPrediction structure
          // Note: This transformation logic mimics what was in App.tsx
          // In a real app, this might be unified in the service or a helper
          const predictions: MatchPrediction[] = matches.map((m) => ({
            match: m,
            prediction: {
              match_id: m.id,
              confidence: 0,
              home_win_probability: 0,
              draw_probability: 0,
              away_win_probability: 0,
              over_25_probability: 0,
              under_25_probability: 0,
              predicted_home_goals: 0,
              predicted_away_goals: 0,
              recommended_bet: "N/A",
              over_under_recommendation: "N/A",
              data_sources: [],
              created_at: new Date().toISOString(),
            },
          }));
          setSearchMatches(predictions);
        } catch (e) {
          setSearchMatches([]);
        } finally {
          setLoading(false);
        }
      } else {
        setSearchMatches([]);
      }
    }, 1000);

    return () => clearTimeout(delayDebounceFn);
  }, [searchQuery]);

  const resetSearch = () => {
    setSearchQuery("");
    setSearchMatches([]);
    setLoading(false);
  };

  return {
    searchQuery,
    setSearchQuery,
    searchMatches,
    loading,
    resetSearch,
  };
}

import { apiClient } from "./client";
import {
  LiveMatchPrediction,
  MatchPrediction,
  Match,
} from "../../domain/entities";
import { fetchESPNLiveMatches } from "../external/espn";
import { API_ENDPOINTS, APP_CONFIG } from "../../config/constants";

export const liveApi = {
  /**
   * Get all live matches globally
   */
  async getLiveMatches(): Promise<Match[]> {
    const response = await apiClient.get<Match[]>(API_ENDPOINTS.MATCHES_LIVE);
    return response.data;
  },

  /**
   * Get live matches with AI predictions
   * Uses backend first, falls back to ESPN if backend empty/fails
   */
  async getLiveMatchesWithPredictions(
    filterTargetLeagues: boolean = true
  ): Promise<LiveMatchPrediction[]> {
    try {
      // 1. Fetch both sources in parallel
      const [backendResponse, espnMatches] = await Promise.all([
        apiClient
          .get<MatchPrediction[]>(API_ENDPOINTS.MATCHES_LIVE_WITH_PREDICTIONS, {
            params: { filter_target_leagues: filterTargetLeagues },
            timeout: APP_CONFIG.API_TIMEOUT,
          })
          .catch(() => ({ data: [] as MatchPrediction[] })), // Soft fail on backend
        fetchESPNLiveMatches(),
      ]);

      const backendMatches = backendResponse.data || [];

      // 2. Map ESPN matches for O(1) lookup (Normalization: lowercase, alphanumeric only)
      const normalize = (name: string) =>
        name.toLowerCase().replace(/[^a-z0-9]/g, "");

      const espnMap = new Map<string, LiveMatchPrediction>();
      espnMatches.forEach((m) => {
        const key = `${normalize(m.match.home_team.name)}-${normalize(
          m.match.away_team.name
        )}`;
        espnMap.set(key, m);
      });

      // 3. Merge Strategy:
      // - Start with Backend matches (they have rich predictions/stats)
      // - VALIDATE against ESPN (if ESPN has data) to filter zombies
      // - If ESPN is empty, fall back to backend? User said "Only ESPN".
      // - Let's use ESPN as the 'Base' list and enrich with Backend predictions.

      // If ESPN is completely down/empty, should we show nothing?
      // "el boton solamente cuando hay partidos en vivo que viene de la api de ESPN"
      // Implies: If ESPN has nothing, show nothing.
      if (espnMatches.length === 0) {
        // Strict Requirement: Only show matches verified by ESPN as Live ("in" or "ht")
        // "el boton solamente cuando hay partidos en vivo que viene de la api de ESPN"
        return [];
      }

      const mergedMatches: LiveMatchPrediction[] = [];
      const usedBackendIds = new Set<string>();

      // Iterate ESPN matches (The Truth)
      espnMatches.forEach((espnMatch) => {
        // Find matching backend prediction
        const espnHome = normalize(espnMatch.match.home_team.name);
        const espnAway = normalize(espnMatch.match.away_team.name);

        const matchingPrediction = backendMatches.find((bp) => {
          const bpHome = normalize(bp.match.home_team.name);
          const bpAway = normalize(bp.match.away_team.name);
          // Check home vs home AND away vs away
          // OR fuzzy partials? Exact normalized match is safest for now.
          return (
            (bpHome.includes(espnHome) || espnHome.includes(bpHome)) &&
            (bpAway.includes(espnAway) || espnAway.includes(bpAway))
          );
        });

        if (matchingPrediction) {
          usedBackendIds.add(matchingPrediction.match.id);
          // Merge: Use Backend Prediction + ESPN Live Stats (usually fresher minute/score)
          // But Backend might have FotMob stats (corners!)
          // Let's keep Backend Match Data but override status/minute from ESPN
          mergedMatches.push({
            ...matchingPrediction,
            match: {
              ...matchingPrediction.match,
              minute: espnMatch.match.minute, // Trust ESPN time
              status: espnMatch.match.status, // Trust ESPN status
              // Keep FotMob stats from backend if available, else use ESPN
              home_corners:
                matchingPrediction.match.home_corners ??
                espnMatch.match.home_corners,
              away_corners:
                matchingPrediction.match.away_corners ??
                espnMatch.match.away_corners,
            },
            isProcessing: false,
          });
        } else {
          // No prediction, just raw ESPN match
          mergedMatches.push(espnMatch);
        }
      });

      return mergedMatches;
    } catch (error) {
      // Final fallback
      return await fetchESPNLiveMatches();
    }
  },
};

import { LiveMatchPrediction } from "../../domain/entities";

// --- Interfaces for ESPN API ---
interface ESPNTeam {
  id: string;
  displayName: string;
  logo?: string;
}

interface ESPNCompetitor {
  id: string;
  homeAway: string;
  team: ESPNTeam;
  score?: string;
}

interface ESPNCompetition {
  competitors: ESPNCompetitor[];
}

interface ESPNStatus {
  type: {
    state: string;
  };
  displayClock: string;
}

interface ESPNEvent {
  id: string;
  status: ESPNStatus;
  competitions: ESPNCompetition[];
}

interface ESPNLeague {
  name: string;
  slug: string;
}

interface ESPNScoreboardResponse {
  leagues?: ESPNLeague[];
  events?: ESPNEvent[];
}

interface ESPNStatistic {
  name: string;
  displayValue: string;
}

interface ESPNTeamBoxscore {
  team: { id: string };
  statistics: ESPNStatistic[];
}

interface ESPNBoxscore {
  teams: ESPNTeamBoxscore[];
}

interface ESPNSummaryResponse {
  boxscore?: ESPNBoxscore;
}

interface MatchToEnrich {
  event: ESPNEvent;
  leagueId: string;
  leagueName: string;
}

// --- Cache Simple para API Pública ---
let publicApiCache: { data: LiveMatchPrediction[]; timestamp: number } | null =
  null;
const CACHE_DURATION = 10000; // 10 segundos de caché para mayor precisión

// Helper para extraer estadísticas del boxscore (Summary API)
const extractStat = (
  boxscore: ESPNBoxscore | undefined,
  teamId: string,
  statName: string | string[]
): number => {
  if (!boxscore || !boxscore.teams) return 0;
  const teamStats = boxscore.teams.find(
    (t) => String(t.team?.id) === String(teamId)
  );
  if (!teamStats || !teamStats.statistics) return 0;
  const names = Array.isArray(statName) ? statName : [statName];
  const stat = teamStats.statistics.find((s) => names.includes(s.name));
  return stat ? parseInt(stat.displayValue) : 0;
};

// --- API Pública de Respaldo (ESPN) ---
export const fetchESPNLiveMatches = async (): Promise<
  LiveMatchPrediction[]
> => {
  const now = Date.now();
  if (publicApiCache && now - publicApiCache.timestamp < CACHE_DURATION) {
    return publicApiCache.data;
  }

  // Slugs de ligas en ESPN (solo las que funcionan correctamente)
  const leagues = [
    "eng.1",
    "eng.2",
    "eng.3", // Inglaterra
    "esp.1",
    "esp.2", // España
    "ita.1",
    "ita.2", // Italia
    "ger.1",
    "ger.2", // Alemania
    "fra.1",
    "fra.2", // Francia
    "por.1", // Primeira Liga
    "ned.1", // Eredivisie
    "bra.1", // Brasileirao
    "arg.1", // Liga Profesional
    "col.1", // Colombia Primera A
    "mex.1", // Liga MX
    "usa.1", // MLS
    "tur.1", // Turquía
    "chn.1", // China
    "jpn.1", // Japón
    "rus.1", // Rusia
    "bel.1", // Bélgica
    "aut.1", // Austria
    "den.1", // Dinamarca
    "swe.1", // Suecia
    "nor.1", // Noruega
    "sco.1", // Escocia
    "uefa.champions", // Champions League
    "uefa.europa", // Europa League
    "conmebol.libertadores",
    "conmebol.sudamericana", // Conmebol
  ];

  try {
    // Hacemos peticiones en paralelo a todas las ligas
    const requests = leagues.map((league) =>
      fetch(
        `https://site.api.espn.com/apis/site/v2/sports/soccer/${league}/scoreboard`
      )
        .then((res) =>
          res.ok ? (res.json() as Promise<ESPNScoreboardResponse>) : null
        )
        .catch(() => null)
    );

    const responses = await Promise.all(requests);
    const liveMatches: LiveMatchPrediction[] = [];
    const matchesToEnrich: MatchToEnrich[] = [];
    const detailRequests: Promise<ESPNSummaryResponse | null>[] = [];

    responses.forEach((data) => {
      if (!data || !data.events) return;

      const leagueName = data.leagues?.[0]?.name || "Torneo Internacional";
      const leagueId = data.leagues?.[0]?.slug || "unknown";

      data.events.forEach((event) => {
        const status = event.status?.type?.state;
        if (status === "in" || status === "ht") {
          matchesToEnrich.push({ event, leagueId, leagueName });
          // Solicitar detalles (summary) para obtener corners y tarjetas
          detailRequests.push(
            fetch(
              `https://site.api.espn.com/apis/site/v2/sports/soccer/${leagueId}/summary?event=${event.id}`
            )
              .then((res) =>
                res.ok ? (res.json() as Promise<ESPNSummaryResponse>) : null
              )
              .catch(() => null)
          );
        }
      });
    });

    // Obtener detalles en paralelo
    const detailsResponses = await Promise.all(detailRequests);

    // Combinar datos básicos con detalles
    matchesToEnrich.forEach((item, index) => {
      const { event, leagueId, leagueName } = item;
      const details = detailsResponses[index];
      const boxscore = details?.boxscore;

      const competition = event.competitions?.[0];
      const competitors = competition?.competitors || [];
      const home = competitors.find((c) => c.homeAway === "home");
      const away = competitors.find((c) => c.homeAway === "away");

      if (home && away) {
        const status = event.status?.type?.state;

        // Construct the LiveMatchPrediction object manually to match domain entity
        liveMatches.push({
          match: {
            id: event.id,
            home_team: {
              id: home.team.id,
              name: home.team?.displayName || "Local",
              logo_url: home.team?.logo,
            },
            away_team: {
              id: away.team.id,
              name: away.team?.displayName || "Visitante",
              logo_url: away.team?.logo,
            },
            league: { id: leagueId, name: leagueName, country: "" },
            match_date: new Date().toISOString(), // Approximation
            home_goals: parseInt(home.score || "0"),
            away_goals: parseInt(away.score || "0"),
            status: status === "ht" ? "HT" : "LIVE",
            home_corners: extractStat(boxscore, home.team.id, [
              "corners",
              "wonCorners",
            ]),
            away_corners: extractStat(boxscore, away.team.id, [
              "corners",
              "wonCorners",
            ]),
            home_yellow_cards: extractStat(
              boxscore,
              home.team.id,
              "yellowCards"
            ),
            away_yellow_cards: extractStat(
              boxscore,
              away.team.id,
              "yellowCards"
            ),
            home_red_cards: extractStat(boxscore, home.team.id, "redCards"),
            away_red_cards: extractStat(boxscore, away.team.id, "redCards"),
            minute: event.status.displayClock,
            // Extended Stats
            home_possession:
              extractStat(boxscore, home.team.id, [
                "possessionPct",
                "possession",
              ]) + "%",
            away_possession:
              extractStat(boxscore, away.team.id, [
                "possessionPct",
                "possession",
              ]) + "%",
            home_shots_on_target: extractStat(boxscore, home.team.id, [
              "shotsOnGoal",
              "ontargetScoringAttempts",
            ]),
            away_shots_on_target: extractStat(boxscore, away.team.id, [
              "shotsOnGoal",
              "ontargetScoringAttempts",
            ]),
            home_total_shots: extractStat(boxscore, home.team.id, [
              "totalShots",
              "sh",
            ]),
            away_total_shots: extractStat(boxscore, away.team.id, [
              "totalShots",
              "sh",
            ]),
            home_fouls: extractStat(boxscore, home.team.id, [
              "foulsCommitted",
              "fouls",
            ]),
            away_fouls: extractStat(boxscore, away.team.id, [
              "foulsCommitted",
              "fouls",
            ]),
            home_offsides: extractStat(boxscore, home.team.id, "offsides"),
            away_offsides: extractStat(boxscore, away.team.id, "offsides"),
          },
          prediction: {
            match_id: event.id,
            home_win_probability: 0,
            draw_probability: 0,
            away_win_probability: 0,
            over_25_probability: 0,
            under_25_probability: 0,
            predicted_home_goals: 0,
            predicted_away_goals: 0,
            confidence: 0,
            data_sources: ["ESPN"],
            recommended_bet: "N/A",
            over_under_recommendation: "N/A",
            created_at: new Date().toISOString(),
          },
          // Custom property for minute if we want to add it to domain later, or check if Match already supports it.
          // The Match entity doesn't have 'minute', maybe we should add it or use status.
          // For now, let's keep it simple.
        });
      }
    });

    publicApiCache = { data: liveMatches, timestamp: Date.now() };
    return liveMatches;
  } catch (error) {
    return [];
  }
};

import localforage from "localforage";
import { StateStorage } from "zustand/middleware";

// Initialize localforage with a dedicated store for Zustand
localforage.config({
  name: "BJJ-BetSports",
  version: 1.0,
  storeName: "app_state",
  description:
    "Persistent storage for BJJ-BetSports application state using IndexedDB",
});

/**
 * Custom storage adapter for Zustand's persist middleware using localforage.
 * This provides significantly larger storage capacity (IndexedDB) than localStorage.
 */
export const indexedDBStorage: StateStorage = {
  getItem: async (name: string): Promise<string | null> => {
    try {
      const value = await localforage.getItem<any>(name);
      if (!value) return null;
      // Zustand expect a string, but localforage can store objects.
      // We stringify to maintain compatibility with Zustand's default JSON parser
      return JSON.stringify(value);
    } catch (error) {
      console.warn(`Error reading ${name} from IndexedDB:`, error);
      return null;
    }
  },
  setItem: async (name: string, value: string): Promise<void> => {
    try {
      // Parse the value before storing if you want to store objects directly in localforage,
      // but Zustand already stringifies for createJSONStorage.
      // So we just store it.
      await localforage.setItem(name, JSON.parse(value));
    } catch (error) {
      console.error(`Error saving ${name} to IndexedDB:`, error);
      // If IndexedDB fails (very rare compared to localStorage), we don't have many options,
      // but at least it won't crash the main execution if handled.
    }
  },
  removeItem: async (name: string): Promise<void> => {
    try {
      await localforage.removeItem(name);
    } catch (error) {
      console.warn(`Error removing ${name} from IndexedDB:`, error);
    }
  },
};

import React from "react";
import { Alert, Button } from "@mui/material";

interface State {
  hasError: boolean;
  error: Error | null;
}

export default class ErrorBoundary extends React.Component<{}, State> {
  constructor(props: {}) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: React.ErrorInfo) {
    // Here you could log to an error tracking service
    // console.error('ErrorBoundary caught', error, info);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: 20 }}>
          <Alert severity="error">
            Ocurrió un error en la aplicación. Por favor recarga la página.
          </Alert>
          <Button
            sx={{ mt: 2 }}
            variant="contained"
            onClick={() => window.location.reload()}
          >
            Recargar
          </Button>
        </div>
      );
    }
    return this.props.children as React.ReactElement;
  }
}

