 * Single live match card with prediction
 */
interface MatchCardProps {
  matchData: LiveMatchPrediction | LiveMatch;
}

// Type guard to check if matchData is a LiveMatchPrediction
const isLiveMatchPrediction = (
  data: LiveMatchPrediction | LiveMatch
): data is LiveMatchPrediction => "match" in data;

// Normalized match data for uniform access
interface NormalizedMatch {
  status: string;
  leagueName: string;
  homeTeamName: string;
  awayTeamName: string;
  homeScore: number;
  awayScore: number;
  homeTeam?: import("../../../types").Team | string;
  awayTeam?: import("../../../types").Team | string;
}

// Normalize match data from either Match or LiveMatch
const normalizeMatch = (
  match: any
): NormalizedMatch => {
  // Check if it's a LiveMatch (has league_name) or Match (has league object)
  if ("league_name" in match) {
    // It's a LiveMatch
    return {
      status: match.status || "LIVE",
      leagueName: match.league_name || "Liga",
      homeTeamName:
        typeof match.home_team === "string"
          ? match.home_team
          : match.home_team.name || "Local",
      awayTeamName:
        typeof match.away_team === "string"
          ? match.away_team
          : match.away_team.name || "Visitante",
      homeTeam: match.home_team,
      awayTeam: match.away_team,
      homeScore: match.home_score ?? 0,
      awayScore: match.away_score ?? 0,
    };
  } else {
    // It's a Match or LiveMatch
    return {
      status: match.status || "LIVE",
      leagueName: (match && match.league && match.league.name) || match.league_name || "Liga",
      homeTeamName:
        typeof match.home_team === "string"
          ? match.home_team
          : match.home_team?.name || "Local",
      awayTeamName:
        typeof match.away_team === "string"
          ? match.away_team
          : match.away_team?.name || "Visitante",
      homeScore: match.home_goals ?? match.home_score ?? 0,
      awayScore: match.away_goals ?? match.away_score ?? 0,
      homeTeam: match.home_team_obj || match.home_team,
      awayTeam: match.away_team_obj || match.away_team,
    };
  }
};

