      {refreshing && (
        <LinearProgress
          sx={{
            mb: 2,
            borderRadius: 1,
            height: 2,
          }}
        />
      )}

      {/* Matches Grid */}
      <Grid container spacing={2}>
        {matches.map((matchData) => (
          <Grid
            size={{ xs: 12, md: 6, lg: 4 }}
